import React, { useState, useEffect } from "react";
import BusMap from "./BusMap";
import BusCharts from "./BusCharts";
import Alerts from "./Alerts";
import "./App.css";

function App() {
  const [buses, setBuses] = useState([]);
  const [alerts, setAlerts] = useState([]);
  const [showChart, setShowChart] = useState(false);

  // Fetch buses and alerts every 2 minutes
  useEffect(() => {
    const fetchBuses = async () => {
      try {
        const res = await fetch("http://127.0.0.1:8000/buses");
        const data = await res.json();
        setBuses(data);
      } catch (err) {
        console.error("Error fetching buses:", err);
      }
    };

    const fetchAlerts = async () => {
      try {
        const res = await fetch("http://127.0.0.1:8000/alerts");
        const data = await res.json();
        setAlerts(data);
      } catch (err) {
        console.error("Error fetching alerts:", err);
      }
    };

    fetchBuses();
    fetchAlerts();
    const interval = setInterval(() => {
      fetchBuses();
      fetchAlerts();
    }, 120000); // 2 minutes

    return () => clearInterval(interval);
  }, []);

  return (
    <div className="App">
      <h1>Ghost Bus Detector</h1>

      {/* Alerts */}
      <Alerts alerts={alerts} />

      {/* Toggle Chart Button */}
      <button onClick={() => setShowChart(!showChart)} className="toggle-chart-btn">
        {showChart ? "Hide Trend Chart" : "Show Trend Chart"}
      </button>

      {/* Trend Chart */}
      {showChart && <BusCharts buses={buses} />}

      {/* Map */}
      <BusMap buses={buses} />
    </div>
  );
}

export default App;
